import { useEffect } from 'react'
import { useRouteMatch } from '@fs/zion-router'
import { useChatDispatch, useChatState } from '../providers/ChatStateProvider'
import streamChatClientEventHandler from '../helpers/stream/streamChatClientEventHandler'
import useChatLog from './useChatLog'

export default function useStreamClientEvents(isOpen) {
  const { client, restrictToManagedGroups } = useChatState()
  const chatDispatch = useChatDispatch()
  const isChat = useRouteMatch('/chat/:cid')
  const isChatThread = useRouteMatch('/chat/:cid/thread/:pid')
  const cid = isChat?.params?.cid || isChatThread?.params?.cid
  const pid = isChatThread?.params?.pid
  const { log } = useChatLog({ component: '[useStreamClientEvents]' })

  useEffect(() => {
    const myClientEventListener =
      isOpen && client
        ? client.on((event) => {
            // Don't process message notification events for restricted users except fs_managed channels
            // This takes care of an edge case where notifications show up when the user was already part of a non-managed channel's threads and there are new messages'
            if (
              (event.type === 'notification.message_new' || event.type === 'notification.invited') &&
              restrictToManagedGroups &&
              event.channel.type !== 'fs_managed'
            )
              return
            streamChatClientEventHandler({ chatDispatch, event, cid, pid, log })
          })
        : null

    return () => {
      if (myClientEventListener) {
        myClientEventListener.unsubscribe()
      }
    }
  }, [log, client, chatDispatch, isOpen, cid, pid, restrictToManagedGroups])
}
