import React, { Suspense, lazy, createRef } from 'react'
import { ShadowScroller, GridStart, ResponsiveProvider } from '@fs/zion-ui/quarks-authorized-use-only'
import { Switch, Route, Redirect, AuthRoute, useRouteMatch } from '@fs/zion-router'
import { colors, useContainerWidth, Bleedable, LayoutBand, Row, Tabs, Tab } from '@fs/zion-ui'
import { css } from '@linaria/core'
import { useTranslation } from 'react-i18next'
import { SocialComment } from '@fs/zion-icon'
import LoadingSpinner from '../chat-window/LoadingSpinner'
import ChatLoadingIndicator from '../chat-window/ChatLoadingIndicator'
import { useChatDispatch, useChatState } from '../providers/ChatStateProvider'
import useSoundNotification from '../hooks/useSoundNotification'
import useStreamClientEvents from '../hooks/useStreamClientEvents'
import usePanelArrowNavigation from '../hooks/usePanelArrowNavigation'
import useChatFlags from '../hooks/useChatFlags'
import { CHAT_ACTIONS } from '../hooks/useChatReducer'
import { buildChatRoute, CHAT_ROUTE_KEY } from './ChatMemoryRouter'
import { TAB_CATEGORY, CHANNEL_TYPE, EVENT_CHANNEL_TYPES } from '../services/fsChat/fsChannelEnums'

const AccessRestrictedError = lazy(() => import('../chat-error/AccessRestrictedError'))
AccessRestrictedError.displayName = 'AccessRestrictedError'
const ChatWindowHeader = lazy(() => import('../chat-window/ChatWindowHeader'))
ChatWindowHeader.displayName = 'ChatWindowHeader'
const ChatHeader = lazy(() => import('../chat-header/ChatHeader'))
ChatHeader.displayName = 'ChatHeader'
const Chat = lazy(() => import('../chat/Chat'))
Chat.displayName = 'Chat'
const ChatWindowHeaderSearch = lazy(() => import('../chat-window/ChatWindowHeaderSearch'))
ChatWindowHeaderSearch.displayName = 'ChatWindowHeaderSearch'
const ChatCreate = lazy(() => import('../chat-create/ChatCreate'))
ChatCreate.displayName = 'ChatCreate'
const ChatDetails = lazy(() => import('../chat-details/ChatDetails'))
ChatDetails.displayName = 'ChatDetails'
const ChatHelperTab = lazy(() => import('../chat-helper-tab/ChatHelperTab'))
ChatHelperTab.displayName = 'ChatHelperTab'
const ChatWindowChats = lazy(() => import('../chat-window/chat-window-chats/ChatWindowChats'))
ChatWindowChats.displayName = 'ChatWindowChats'
const ChatReconnectPage = lazy(() => import('../chat-reconnect/ChatReconnectPage'))
ChatReconnectPage.displayName = 'ChatReconnectPage'
const ChatBlockedContent = lazy(() => import('../chat-blocked/ChatBlockedContent'))
ChatBlockedContent.displayName = 'ChatBlockedContent'
const ChatHiddenContent = lazy(() => import('../chat-hidden/ChatHiddenContent'))
ChatHiddenContent.displayName = 'ChatHiddenContent'
const ChatOptions = lazy(() => import('../chat-options/ChatOptions'))
ChatOptions.displayName = 'ChatOptions'
const EmbeddedChatFallback = lazy(() => import('../embedded-chat/EmbeddedChatFallback'))
EmbeddedChatFallback.displayName = 'EmbeddedChatFallback'

const scrollerRef = React.createRef()

const leftContent = createRef()
const rightContent = createRef()
const threadContent = createRef()

const doubleScrollyCss = css`
  display: flex; //Defaults to flex-direction: row, so things are side-by-side
  flex-grow: 1;
  flex-shrink: 1;
  overflow: hidden;
`

const leftCss = css`
  display: flex;
  flex-direction: column; // strech down if there is no content
  flex-basis: 380px;
  min-width: 380px;
  overflow: hidden;
  border-inline-end: 1px solid ${colors.transparent.gray20};
`

const singleColumnCss = css`
  display: flex;
  flex-direction: column; // stretch down if there is no content
  flex-basis: 100%;
  min-width: 260px; // single-column view is used in narrow embedded chats
  min-height: 420px;
  flex-grow: 1;
`

const rightCss = css`
  flex-grow: 2; //take up the rest of the width
  flex-direction: column; // strech down if there is no content
  flex-shrink: 1;
  overflow: hidden;
  display: flex;
  flex-basis: 380px;
  min-width: 260px;
`

const farRightCss = css`
  flex-grow: 1; //take up the rest of the width
  flex-direction: column; // stretch down if there is no content
  flex-shrink: 2;
  overflow: hidden;
  display: flex;
  border-inline-start: 1px solid ${colors.transparent.gray20};
  flex-basis: 380px;
  min-width: 380px;
`

// Negative margin-bottom to offset InputBase margin-bottom
const subheaderCss = css`
  margin: 12px 0 -12px;
`

const skipLinkCss = css`
  position: absolute;
  inset-inline: -10000px;
  top: auto;
  width: 1px;
  height: 1px;
  overflow: hidden;
`

const useChatSize = () => {
  const atWidth = useContainerWidth()
  const wide = atWidth({ default: false, lg: true })
  const extraWide = atWidth({ default: false, xxl: true })
  return { wide, extraWide }
}

export const Header = () => {
  const { connectError, personalDataError } = useChatState()
  const { wide } = useChatSize()
  if (connectError || personalDataError) return null

  return (
    <Suspense>
      <Switch>
        <AuthRoute path="/chat-window/:type">
          <ChatWindowHeader />
        </AuthRoute>
        <AuthRoute path="/chat-blocked">{wide ? <ChatWindowHeader /> : <ChatHeader />}</AuthRoute>
        <AuthRoute path="/chat-hidden">{wide ? <ChatWindowHeader /> : <ChatHeader />}</AuthRoute>
        <AuthRoute path="/chat/:cid/thread/:pid">{wide ? <ChatWindowHeader /> : <ChatHeader />}</AuthRoute>
        <AuthRoute path="/chat/:cid">{wide ? <ChatWindowHeader /> : <ChatHeader />}</AuthRoute>
        <AuthRoute path="/chat-create/:type">{wide ? <ChatWindowHeader /> : <ChatHeader />}</AuthRoute>
        <AuthRoute path="*">
          <Redirect from="*" to="/chat-window/chats" />
        </AuthRoute>
      </Switch>
    </Suspense>
  )
}

export const ChatTabs = () => {
  const [t] = useTranslation()
  const chatDispatch = useChatDispatch()
  const { channels, threadList, restrictToManagedGroups } = useChatState()

  const unreadChannels = channels.filter((channel) => channel?.countUnread() > 0)
  const unreadThreads = threadList.filter((thread) => thread?.ownUnreadCount > 0)
  const familyGroupsUnread = channels
    .filter((c) => c.type === CHANNEL_TYPE.FS_MANAGED)
    .filter((c) => c?.countUnread() > 0)
  const directUnread = channels.filter((c) => c.type === CHANNEL_TYPE.FS_DIRECT).filter((c) => c?.countUnread() > 0)

  const chatCategories = [
    {
      key: TAB_CATEGORY.ALL,
      label: t('chat.tab.all', 'All'),
      count: null,
    },
    {
      key: TAB_CATEGORY.UNREAD,
      label: t('chat.tab.unread', 'Unread'),
      count: unreadChannels.length + unreadThreads.length || null,
    },
    {
      key: TAB_CATEGORY.DIRECT,
      label: t('chat.tab.direct', 'Direct'),
      count: directUnread.length || null,
    },
    {
      key: TAB_CATEGORY.FAMILY_GROUPS,
      label: t('chat.tab.family-groups', 'Family Groups'),
      count: familyGroupsUnread.length || null,
    },
    {
      key: TAB_CATEGORY.THREADS,
      label: t('chat.tab.threads', 'Threads'),
      count: unreadThreads.length || null,
    },
  ]

  if (!restrictToManagedGroups) {
    const unreadEvents = channels
      .filter((c) => EVENT_CHANNEL_TYPES.includes(c.type))
      .filter((c) => c?.countUnread() > 0)
    chatCategories.push({
      key: TAB_CATEGORY.EVENTS,
      label: t('chat.tab.events', 'Events'),
      count: unreadEvents.length || null,
    })
  }

  return (
    <>
      <a
        href="#chat-content"
        className={skipLinkCss}
        onClick={(e) => {
          e.preventDefault()
          const el = document.getElementById('chat-content')
          if (el) el.focus()
        }}
      >
        {t('chat.skip-to-content', 'Skip to chat content')}
      </a>

      <Row gutters="none">
        <Tabs
          growX
          noShrinkX
          onChange={(index) =>
            chatDispatch({ type: CHAT_ACTIONS.SET_CHAT_CATEGORY, chatCategory: chatCategories[index].key })
          }
        >
          {chatCategories.map((category) => (
            <Tab key={category.key} title={category.label} count={category.count} />
          ))}
        </Tabs>
        <ChatOptions />
      </Row>
    </>
  )
}

const ChatSearchSubHeader = ({ isOnCreateNewChat }) => {
  const { connectError, personalDataError } = useChatState()
  if (connectError || personalDataError) return null

  return (
    <div className={subheaderCss}>
      <ChatWindowHeaderSearch isOnCreateNewChat={isOnCreateNewChat} />
    </div>
  )
}

const PickAConversation = () => {
  const [t] = useTranslation()

  return (
    <LayoutBand color={colors.gray03} alignY="middle">
      <Row alignX="center" alignY="bottom" gutters="xxs">
        <SocialComment />
        {t('chat.select-a-chat.message', 'Select a chat to start messaging.')}
      </Row>
    </LayoutBand>
  )
}

export const SubHeader = () => {
  const { wide } = useChatSize()
  const isHelperTab = useRouteMatch(buildChatRoute(CHAT_ROUTE_KEY.HELPER))
  if (isHelperTab) return null

  return (
    <Suspense>
      <Switch>
        <AuthRoute path="/chat-window/:type" component={ChatSearchSubHeader} />
        <Route path="*">
          {wide && (
            <Switch>
              <AuthRoute path="/chat-create/:type">
                <ChatSearchSubHeader isOnCreateNewChat />
              </AuthRoute>
              <AuthRoute path="/*" component={ChatSearchSubHeader} />
            </Switch>
          )}
        </Route>
      </Switch>
    </Suspense>
  )
}

const flexGrowyCss = css`
  display: flex;
  flex-direction: column;
  flex: 1;
`

const ScrollZone = ({ children, ...props }) => {
  return (
    <ShadowScroller ref={scrollerRef} {...props}>
      <Bleedable className={flexGrowyCss} sides={14} top={0}>
        <ResponsiveProvider className={flexGrowyCss}>
          <GridStart className={flexGrowyCss}>{children}</GridStart>
        </ResponsiveProvider>
      </Bleedable>
    </ShadowScroller>
  )
}

const LeftContentPanel = () => {
  const { messagingChatLeftPanelRedesignIsOn } = useChatFlags()

  return (
    <Suspense>
      <div className={leftCss} data-testid="chat-left-content-panel" ref={leftContent} tabIndex={-1}>
        <ScrollZone id="left-content-scroll-zone">
          <Switch>
            <AuthRoute exact path="/chat-create/:type" component={ChatWindowChats} />
            <AuthRoute path="/chat/:cid" component={ChatWindowChats} />
            <AuthRoute path="*" component={ChatWindowChats} />
          </Switch>
        </ScrollZone>
        {!messagingChatLeftPanelRedesignIsOn && <ChatOptions />}
      </div>
    </Suspense>
  )
}

const RightContentPanel = ({ supportInformation, extraWide }) => {
  return (
    <Suspense fallback={<ChatLoadingIndicator />}>
      <div className={rightCss} data-testid="chat-right-content-panel" ref={rightContent} tabIndex={-1}>
        <Switch>
          <AuthRoute path="/chat-blocked">
            <ChatBlockedContent />
          </AuthRoute>
          <AuthRoute path="/chat-hidden">
            <ChatHiddenContent />
          </AuthRoute>
          <AuthRoute path="/chat-window/:type" component={PickAConversation} />
          <AuthRoute path="/chat/:cid/thread/:pid">
            <Chat isThread={!extraWide} />
          </AuthRoute>
          <AuthRoute path="/chat/:cid/:subpage">
            <ChatDetails />
          </AuthRoute>
          <AuthRoute path="/chat/:cid">
            <Chat />
          </AuthRoute>
          <AuthRoute path="/chat-create/:type">
            <ChatCreate supportInformation={supportInformation} />
          </AuthRoute>
          <AuthRoute path="*" component={PickAConversation} />
        </Switch>
      </div>
    </Suspense>
  )
}

const ThreadContentPanel = () => {
  return (
    <Suspense fallback={<LoadingSpinner />}>
      <Switch>
        <AuthRoute path="/chat/:cid/thread/:pid">
          <div className={farRightCss} data-testid="chat-thread-content-panel" ref={threadContent} tabIndex={-1}>
            <Chat isThread />
          </div>
        </AuthRoute>
      </Switch>
    </Suspense>
  )
}

const SingleContentPanel = ({ supportInformation }) => {
  const { messagingChatLeftPanelRedesignIsOn } = useChatFlags()

  return (
    <Suspense fallback={<LoadingSpinner />}>
      <div className={singleColumnCss} id="left-content-scroll-zone" data-testid="chat-single-content-panel">
        <Switch>
          <AuthRoute path="/chat-blocked">
            <ChatBlockedContent isNarrow />
          </AuthRoute>
          <AuthRoute path="/chat-hidden">
            <ChatHiddenContent isNarrow />
          </AuthRoute>
          <AuthRoute exact path="/chat-window/chats">
            <ScrollZone>
              <ChatWindowChats />
            </ScrollZone>
            {!messagingChatLeftPanelRedesignIsOn && <ChatOptions />}
          </AuthRoute>
          <AuthRoute path="/chat/:cid/thread/:pid">
            <Chat isThread isNarrow />
          </AuthRoute>
          <AuthRoute path="/chat/:cid/:subpage">
            <ChatDetails />
          </AuthRoute>
          <AuthRoute path="/chat/:cid">
            <Chat />
          </AuthRoute>
          <AuthRoute path="/chat-create/:type">
            <ChatCreate supportInformation={supportInformation} />
          </AuthRoute>
          <AuthRoute path="*">
            <ScrollZone>
              <ChatWindowChats />
            </ScrollZone>
            {!messagingChatLeftPanelRedesignIsOn && <ChatOptions />}
          </AuthRoute>
        </Switch>
      </div>
    </Suspense>
  )
}

export const Content = ({ supportInformation, isOpen }) => {
  const { wide, extraWide } = useChatSize()
  const { connectError, personalDataError } = useChatState()
  const isHelperTab = useRouteMatch(buildChatRoute(CHAT_ROUTE_KEY.HELPER))
  const { messagingChatLeftPanelRedesignIsOn, messagingChatHelperIsOn, chatPrefsLoading } = useChatFlags()

  // if we are on wide or extrawide view, always show tabs
  // otherwise, calculate if we should show the tabs based on route
  const isOnChatWindow = useRouteMatch({ path: '/chat-window/chats', exact: true })
  const isOnOtherRoutes = useRouteMatch({
    path: ['/chat-blocked', '/chat-hidden', '/chat/:cid', '/chat-create/:type'],
    exact: false,
  })
  const showSmallViewTabs = isOnChatWindow || !isOnOtherRoutes

  useStreamClientEvents(isOpen)
  useSoundNotification(isOpen)
  usePanelArrowNavigation({ leftContent, rightContent, threadContent, extraWide })

  if (personalDataError) return <AccessRestrictedError />
  if (isHelperTab && !chatPrefsLoading && !messagingChatHelperIsOn) {
    return <Redirect to={buildChatRoute(CHAT_ROUTE_KEY.CHATS)} />
  }
  if (isHelperTab) {
    return (
      <Suspense fallback={<LoadingSpinner />}>
        <ChatHelperTab />
      </Suspense>
    )
  }
  if (connectError) {
    return (
      <Suspense fallback={<LoadingSpinner />}>
        <ChatReconnectPage />
      </Suspense>
    )
  }
  return (
    <>
      {messagingChatLeftPanelRedesignIsOn && (wide || extraWide || showSmallViewTabs) && <ChatTabs />}
      <div id="chat-content" className={doubleScrollyCss} data-testid="chat-content" tabIndex={-1}>
        {!wide && !extraWide && <SingleContentPanel supportInformation={supportInformation} />}
        {wide && (
          <>
            <LeftContentPanel />
            <RightContentPanel supportInformation={supportInformation} wide={wide} extraWide={extraWide} />
            {extraWide && <ThreadContentPanel />}
          </>
        )}
      </div>
    </>
  )
}

export const EmbeddedChatContent = ({ supportInformation, header, userReady, onClose, chatRestricted }) => {
  const { connectError, personalDataError, renderFallback } = useChatState()
  useStreamClientEvents(true)

  if (renderFallback) return <EmbeddedChatFallback onClose={onClose} chatRestricted={chatRestricted} />

  let errorPage
  if (personalDataError && userReady) errorPage = <AccessRestrictedError />
  if (connectError && userReady) errorPage = <ChatReconnectPage isEmbedded />

  return (
    <Suspense fallback={<LoadingSpinner />}>
      <div className={singleColumnCss}>
        {userReady && (
          <>
            {header}
            {errorPage || <RightContentPanel supportInformation={supportInformation} />}
          </>
        )}
      </div>
    </Suspense>
  )
}
