import React, { useState } from 'react'
import ErrorBoundary from '@fs/zion-error-boundary'
import { useHistory } from '@fs/zion-router'
import { LOG_LEVEL } from '../global/chatLog'
import useChatLog from '../hooks/useChatLog'
import { CHAT_ROUTE_KEY, buildChatRoute } from '../chat-memory-router/ChatMemoryRouter'
import ChatReconnectPage from '../chat-reconnect/ChatReconnectPage'

export default function ChatErrorBoundary({ children }) {
  const history = useHistory()
  const { log } = useChatLog({ component: '[ChatErrorBoundary]' })
  const [errorCount, setErrorCount] = useState(0)
  const handleError = (error, info) => {
    log({ msg: `ErrorBoundary caught ${error} ${info}`, level: LOG_LEVEL.ERROR })
    history.push(buildChatRoute(CHAT_ROUTE_KEY.CHATS))
    if (errorCount <= 3) setErrorCount(errorCount + 1)
  }

  // eslint-disable-next-line react/no-unstable-nested-components -- This is not a big deal because we want to rerender the subtree anyway
  const FallbackComponent = () => {
    return <ChatReconnectPage isEmbedded={false} onClick={handleError} />
  }

  return (
    <ErrorBoundary FallbackComponent={FallbackComponent} key={errorCount} errorHandler={handleError}>
      {children}
    </ErrorBoundary>
  )
}
