import React, { useContext, useReducer } from 'react'

export const actionTypes = {
  SET_MULTI_SELECT_IS_ACTIVE: 'SET_MULTI_SELECT_IS_ACTIVE',
  SET_SELECTED_CHANNELS: 'SET_SELECTED_CHANNELS',
  CLEAR_SELECTED_CHANNELS: 'CLEAR_SELECTED_CHANNELS',
  TOGGLE_CHANNEL_SELECTION: 'TOGGLE_CHANNEL_SELECTION',
}

const initialState = {
  multiSelectIsActive: false,
  selectedChannels: new Set(),
}

const multiSelectStateReducer = (state, action) => {
  switch (action.type) {
    case actionTypes.SET_MULTI_SELECT_IS_ACTIVE:
      return { ...state, multiSelectIsActive: action.multiSelectIsActive }
    case actionTypes.SET_SELECTED_CHANNELS:
      return { ...state, selectedChannels: new Set(action.channels) }
    case actionTypes.CLEAR_SELECTED_CHANNELS:
      return { ...state, selectedChannels: new Set() }
    case actionTypes.TOGGLE_CHANNEL_SELECTION: {
      const updatedSelection = new Set(state.selectedChannels)
      if (updatedSelection.has(action.cid)) {
        updatedSelection.delete(action.cid)
      } else {
        updatedSelection.add(action.cid)
      }
      return { ...state, selectedChannels: updatedSelection }
    }
    default:
      return state
  }
}

const ChatMultiSelectContext = React.createContext()
const ChatMultiSelectDispatchContext = React.createContext()

export const useChatMultiSelectState = () => {
  return useContext(ChatMultiSelectContext)
}

export const useChatMultiSelectDispatch = () => {
  return useContext(ChatMultiSelectDispatchContext)
}

export function useChatMultiSelectProviderData() {
  const [multiSelectState, multiSelectDispatch] = useReducer(multiSelectStateReducer, initialState)
  return { multiSelectState, multiSelectDispatch }
}

export default function ChatMultiSelectProvider({ children, chatMultiSelectProviderData }) {
  const { multiSelectState, multiSelectDispatch } = chatMultiSelectProviderData

  return (
    <ChatMultiSelectContext.Provider value={multiSelectState}>
      <ChatMultiSelectDispatchContext.Provider value={multiSelectDispatch}>
        {children}
      </ChatMultiSelectDispatchContext.Provider>
    </ChatMultiSelectContext.Provider>
  )
}
