import React, { useContext, useEffect, useMemo, useState } from 'react'
import { useUser } from '@fs/zion-user'
import { useEvent } from '@fs/zion-frontend-friends'
import { CHANNEL_TYPE } from '../services/fsChat/fsChannelEnums'
import chatLog, { LOG_LEVEL } from '../global/chatLog'
import {
  CHAT_PREF,
  getChatPreference,
  setChatPreference,
} from '../services/chatUserPreferenceService/chatUserPreferenceService'

export const initialState = {
  // Which sections are expanded (all except Threads by default)
  ...Object.values(CHANNEL_TYPE).reduce((state, key) => {
    state[key] = true
    return state
  }, {}),
  [CHANNEL_TYPE.FS_THREAD]: false,
}

const ChatChannelExpanderContext = React.createContext()

export const useChatChannelExpander = () => {
  return useContext(ChatChannelExpanderContext)
}

export function useChatChannelExpanderProviderData() {
  const [expandable, setExpandable] = useState(initialState)
  const [expandableLoaded, setExpandableLoaded] = useState(false)
  const user = useUser()
  const { cisId } = user

  useEffect(() => {
    let isUnmounted = false

    async function getExpandable() {
      try {
        const newExpandable = await getChatPreference(CHAT_PREF.EXPANDABLE, initialState)

        if (!isUnmounted) {
          setExpandable({ ...initialState, ...newExpandable })
          setExpandableLoaded(true)
        }
      } catch (err) {
        if (!isUnmounted) {
          chatLog({
            msg: `Failed to get preference (${CHAT_PREF.EXPANDABLE}): ${err}`,
            component: '[useChatChannelExpanderProviderData]',
            user: { cisId },
            level: LOG_LEVEL.ERROR,
          })
          setExpandableLoaded(true)
        }
      }
    }

    if (cisId) {
      getExpandable()
    }

    return () => {
      isUnmounted = true
    }
  }, [cisId])

  const updateExpandableItem = useEvent(async ({ isOpen, key }) => {
    if (expandable[key] !== isOpen) {
      try {
        const updatedExpandable = { ...expandable }
        updatedExpandable[key] = isOpen
        setExpandable(updatedExpandable)
        await setChatPreference(CHAT_PREF.EXPANDABLE, updatedExpandable)
      } catch (err) {
        chatLog({
          msg: `setPreference (${CHAT_PREF.EXPANDABLE}) failed! - ${err}`,
          component: '[useChatChannelExpanderProviderData]',
          user: { cisId },
          level: LOG_LEVEL.ERROR,
        })
      }
    }
  })
  return { expandable, expandableLoaded, updateExpandableItem }
}

export default function ChatChannelExpanderProvider({ children, chatChannelExpanderProviderData }) {
  const { expandable, expandableLoaded, updateExpandableItem } = chatChannelExpanderProviderData
  const value = useMemo(
    () => ({ expandable, expandableLoaded, updateExpandableItem }),
    [expandable, expandableLoaded, updateExpandableItem]
  )

  return <ChatChannelExpanderContext.Provider value={value}>{children}</ChatChannelExpanderContext.Provider>
}
