import { useEffect } from 'react'
import chatLog, { LOG_LEVEL } from '../global/chatLog'

// Purchased by Robb Perry from Pond5 under a commercial licence
// This is lazily loaded in practice: this import is webpack providing the CDN URL, but the browser only downloads it when triggered in playNotifySound()
import newMessageSound from '../assets/new-message.mp3'
import { useChatDispatch, useChatState } from '../providers/ChatStateProvider'
import { CHAT_ACTIONS } from './useChatReducer'

const soundEffect = new Audio()
soundEffect.autoplay = true

const initialSoundCallback = () => {
  // a small silent mp3 created by us with `ffmpeg -f lavfi -i anullsrc=r=44100:cl=mono -t 0.01 -b:a 1k -acodec libmp3lame out.mp3 && base64 out.mp3`
  soundEffect.src =
    'data:audio/mpeg;base64,'
  document.removeEventListener('touchstart', initialSoundCallback)
  document.removeEventListener('mousedown', initialSoundCallback)
}
// this listener is removed as soon as the first user touch/mousedown happens on the page, it is needed to get around Safari's sound only-with-user-interaction requirement
document.addEventListener('touchstart', initialSoundCallback)
document.addEventListener('mousedown', initialSoundCallback)

export function playNotifySound(sound) {
  soundEffect.src = sound || newMessageSound
}

export default function useSoundNotification(isOpen) {
  const { soundEnabled, playSound, user } = useChatState()
  const chatDispatch = useChatDispatch()

  useEffect(() => {
    try {
      if (isOpen && playSound && soundEnabled) {
        playNotifySound(newMessageSound)
      }
    } catch (e) {
      chatLog({
        msg: 'Error playing sound notification!',
        level: LOG_LEVEL.ERROR,
        user: { id: user?.cisId },
      })
    }
    chatDispatch({ type: CHAT_ACTIONS.CLEAR_PLAY_SOUND })
  }, [chatDispatch, playSound, isOpen, soundEnabled, user?.cisId])
}
