import Cache from '@fs/zion-cache'
import { CHAT_ACTIONS } from '../../hooks/useChatReducer'
import { LOG_LEVEL } from '../../global/chatLog'

// Store timeout to prevent stale connection.changed events from showing reconnect page after connection recovers
let connectionChangedTimeout = null

function logStreamChatClientEventHandler({ event, cid, pid, log }) {
  const { channel, message, cid: eventCid = '', type } = event
  const eventString = `Stream Event "${type}" cid:${eventCid || cid} pid:${pid || ''}`
  const { cid: channelId = '' } = channel || {}
  const channelString = channel ? `\n  channel <-- cid:${channelId} -->` : ''
  const { id: messageId = '', text = '', reply_count = 0 } = message || {}
  const messageString = message ? `\n  message <- id:${messageId} "${text}" reply_count=${reply_count} -->` : ''

  log({ msg: `${eventString}${channelString}${messageString}`, level: LOG_LEVEL.LOG })
}

export default function streamChatClientEventHandler({ chatDispatch, event, cid, pid, log }) {
  logStreamChatClientEventHandler({ event, cid, pid, log })
  const cache = new Cache({ storeName: 'chatMessageTranslations' })
  // eslint-disable-next-line sonarjs/max-switch-cases -- we need to handle all of these events
  switch (event.type) {
    case 'connection.changed':
      // Clear any pending connection changed dispatch to prevent stale offline events from showing reconnect page
      if (connectionChangedTimeout) {
        clearTimeout(connectionChangedTimeout)
      }
      // The delay is to prevent prematurely showing the error state until SET_AUTHENTICATING has hopefully been dispatched
      connectionChangedTimeout = setTimeout(() => {
        chatDispatch({ type: CHAT_ACTIONS.CONNECTION_CHANGED, online: event.online, cid })
        connectionChangedTimeout = null
      }, 2000)
      break
    case 'connection.recovered':
      chatDispatch({ type: CHAT_ACTIONS.CONNECTION_RECOVERED, event, cid })
      break
    case 'notification.invited':
      chatDispatch({ type: CHAT_ACTIONS.INVITED, event })
      break
    case 'notification.added_to_channel':
      chatDispatch({ type: CHAT_ACTIONS.ADDED_TO_CHANNEL, event })
      break
    case 'channel.hidden':
      chatDispatch({ type: CHAT_ACTIONS.HIDDEN, event })
      break
    case 'channel.visible':
      chatDispatch({ type: CHAT_ACTIONS.VISIBLE, event })
      break
    case 'channel.updated':
      chatDispatch({ type: CHAT_ACTIONS.CHANNEL_UPDATED, event, cid })
      break
    case 'notification.invite_accepted':
      chatDispatch({ type: CHAT_ACTIONS.INVITE_ACCEPTED, event })
      break
    case 'notification.invite_rejected':
      chatDispatch({ type: CHAT_ACTIONS.INVITE_REJECTED, event })
      break
    case 'notification.mark_read':
      chatDispatch({ type: CHAT_ACTIONS.MARK_READ, event })
      break
    case 'notification.channel_mutes_updated':
      chatDispatch({ type: CHAT_ACTIONS.SET_CHANNEL_MUTES, event })
      break
    case 'notification.thread_message_new':
    case 'notification.message_new':
      chatDispatch({ type: CHAT_ACTIONS.NEW_MESSAGE_NOT_WATCHED, event })
      break
    case 'message.new':
      chatDispatch({ type: CHAT_ACTIONS.NEW_MESSAGE, event, cid, pid })
      break
    case 'notification.mutes_updated':
      chatDispatch({ type: CHAT_ACTIONS.BLOCKED_USERS_UPDATED, event })
      break
    case 'message.deleted':
      chatDispatch({ type: CHAT_ACTIONS.MESSAGE_DELETED, event })
      break
    case 'message.updated':
      chatDispatch({ type: CHAT_ACTIONS.MESSAGE_UPDATED, event })
      cache.setItem(event.message?.id, '')
      break
    case 'reaction.new':
    case 'reaction.updated':
    case 'reaction.deleted':
      chatDispatch({ type: CHAT_ACTIONS.MESSAGE_UPDATED, event })
      break
    case 'notification.removed_from_channel':
      chatDispatch({ type: CHAT_ACTIONS.REMOVED_FROM_CHANNEL, event })
      break
    default:
      break
  }
}
