import { SupplementalOverlay } from '@fs/zion-ui/quarks-authorized-use-only'
import React, { Suspense, lazy } from 'react'
import { Theme } from '@fs/zion-ui'
import ChatMemoryRouter from '../chat-memory-router/ChatMemoryRouter'
import { Content, Header, SubHeader } from '../chat-memory-router/ChatPieces'
import LoadingSpinner from '../chat-window/LoadingSpinner'
import ChatChannelExpanderProvider, {
  useChatChannelExpanderProviderData,
} from '../providers/ChatChannelExpanderProvider'
import ChatAttachmentsProvider, { useChatAttachmentsProviderData } from '../providers/ChatAttachmentsProvider'
import ChatMultiSelectProvider, { useChatMultiSelectProviderData } from '../providers/ChatMultiSelectProvider'
import ChatStateProvider, { useChatStateProviderData } from '../providers/ChatStateProvider'
import { useChatProviderContext } from '../providers/useChatProviderContext'
import ChatErrorBoundary from './ChatErrorBoundary'
import ChatHelpOverview from '../chat-help-overview/ChatHelpOverview'
import { ChatHelperProvider } from '../chat-helper-tab/HelperProvider'
import useHelperConfirmationOverlay from '../hooks/useHelperConfirmationOverlay'

const HelperAvailabilityConfirmDialog = lazy(() => import('../chat-helper-tab/HelperAvailabilityConfirmDialog'))

export default function ChatOverlay({ supportInformation, overlay }) {
  const chatChannelExpanderProviderData = useChatChannelExpanderProviderData()
  const chatAttachmentsProviderData = useChatAttachmentsProviderData()
  const { chatRoute } = useChatProviderContext()

  const chatStateProviderData = useChatStateProviderData({
    isEmbedded: false,
    overlayIsOpen: overlay.isOpen,
    supportChatInformation: supportInformation,
    chatRoute,
  })
  const user = chatStateProviderData?.chatStateValue?.user
  const userReady = user?.userLoading === false && user?.signedIn

  return (
    <ChatStateProvider chatStateProviderData={chatStateProviderData}>
      <Theme theme={chatStateProviderData.chatStateValue.darkMode ? 'night' : 'day'}>
        <ChatChannelExpanderProvider chatChannelExpanderProviderData={chatChannelExpanderProviderData}>
          <ChatAttachmentsProvider chatAttachmentsProviderData={chatAttachmentsProviderData}>
            <ChatHelperProvider isChatOverlayOpen={overlay.isOpen}>
              <ChatOverlayContent
                overlay={overlay}
                supportInformation={supportInformation}
                userReady={userReady}
                chatRoute={chatRoute}
              />
            </ChatHelperProvider>
          </ChatAttachmentsProvider>
        </ChatChannelExpanderProvider>
      </Theme>
    </ChatStateProvider>
  )
}

function ChatOverlayContent({ overlay, supportInformation, userReady, chatRoute }) {
  const { wrappedOverlay, confirmationOverlay } = useHelperConfirmationOverlay(overlay)
  const multiSelectProviderData = useChatMultiSelectProviderData()

  return (
    <ChatMultiSelectProvider chatMultiSelectProviderData={multiSelectProviderData}>
      <ChatMemoryRouter chatRoute={chatRoute}>
        {userReady && (
          <SupplementalOverlay
            defaultWidth={1024}
            defaultHeight={720}
            overlayKey="chatOverlay"
            bleedAmount={0}
            {...wrappedOverlay}
            headerColor="red"
            header={<Header />}
            subHeader={<SubHeader />}
            strippedDownLayout
          >
            <ChatErrorBoundary>
              <Suspense fallback={<LoadingSpinner />}>
                <Content {...wrappedOverlay} supportInformation={supportInformation} />
                <ChatHelpOverview />
                {(confirmationOverlay.isOpen || confirmationOverlay.transitioning) && (
                  <HelperAvailabilityConfirmDialog
                    confirmationOverlay={confirmationOverlay}
                    onConfirm={overlay.close}
                  />
                )}
              </Suspense>
            </ChatErrorBoundary>
          </SupplementalOverlay>
        )}
      </ChatMemoryRouter>
    </ChatMultiSelectProvider>
  )
}
