import { useCallback, useEffect, useState } from 'react'
import { useUserProfile } from '@fs/zion-user'
import { useCache } from '@fs/zion-cache'
import { useOverlay } from '@fs/zion-ui'
import {
  getDiscussions,
  getGeneralists,
  getMyGeneralist,
  setAvailability,
  getStats,
} from '../services/helperQueue/helperQueueService'
import { langs } from '../chat-helper-tab/helpers'
import chatLog, { LOG_LEVEL } from '../global/chatLog'

const COMPONENT_NAME = '[useHelperQueue]'

const usePoll = (callback, frequency) => {
  const [active, setActive] = useState(0)

  const start = useCallback(() => setActive((prev) => prev + 1), []) // lets us use start as a 'restart' as well this way
  const stop = useCallback(() => setActive(0), [])

  useEffect(() => {
    let interval
    if (active) {
      callback() // start immediately, followed by interval
      interval = setInterval(() => {
        // only polling if current tab is visible. Will save resources if helpers have multiple tabs opened.
        if (document.visibilityState === 'visible') {
          callback()
        }
      }, frequency)
    }
    return () => {
      clearInterval(interval)
    }
  }, [active, callback, frequency])

  return { start, stop }
}

const key = 'helperLangsPreference'
const initialValue = langs.slice()
const cache = { storeName: 'generalistsLangFilter' }

const useHelperQueue = ({ mockValue, isChatOverlayOpen }) => {
  const [generalistsData, setGeneralistsData] = useState({})
  const [discussions, setDiscussions] = useState()
  const [generalistsOpen, setGeneralistsOpen] = useState(true)
  const [myStatus, setMyStatus] = useState({})
  const [generalistsLangFilter, setGeneralistsLangFilter] = useCache({ cache, key, initialValue })
  const [stats, setStats] = useState({})
  const { userProfile } = useUserProfile()
  const cisId = userProfile?.cisId
  const filterOverlay = useOverlay()
  const generalistsLangsToString = generalistsLangFilter?.length < 11 ? generalistsLangFilter.join(' ') : ''

  const parseStatusAndSetLangOrder = useCallback(({ data = {} }) => {
    const helpeeLanguages = new Set((data?.languages || '').split(',').map((lang) => lang.trim()))
    const userLangs = langs.slice().sort((lang1, lang2) => {
      const lang1Included = helpeeLanguages.has(lang1)
      const lang2Included = helpeeLanguages.has(lang2)
      if (lang1Included && lang2Included) return 0
      if (lang1Included) return -1
      if (lang2Included) return 1
      return 0
    })

    setMyStatus({ ...data, userLangs })
  }, [])

  const myStatusPoll = useCallback(() => {
    getMyGeneralist()
      .then(parseStatusAndSetLangOrder)
      .catch((reason) => {
        chatLog({
          msg: reason,
          level: LOG_LEVEL.ERROR,
          component: COMPONENT_NAME,
          user: { cisId },
        })
      })
  }, [parseStatusAndSetLangOrder, cisId])

  const statsPoll = useCallback(() => {
    getStats()
      .then(({ data }) => setStats(data))
      .catch((reason) => {
        chatLog({
          msg: reason,
          level: LOG_LEVEL.ERROR,
          component: COMPONENT_NAME,
          user: { cisId },
        })
      })
  }, [cisId])
  const generalistsPoll = useCallback(() => {
    getGeneralists(generalistsLangsToString)
      .then(({ data }) => setGeneralistsData(data))
      .catch((reason) => {
        chatLog({
          msg: reason,
          level: LOG_LEVEL.ERROR,
          component: COMPONENT_NAME,
          user: { cisId },
        })
      })
  }, [generalistsLangsToString, cisId])
  const discussionPoll = useCallback(() => {
    getDiscussions()
      .then(({ data }) => setDiscussions(data?.availableByLanguage))
      .catch((reason) => {
        chatLog({
          msg: reason,
          level: LOG_LEVEL.ERROR,
          component: COMPONENT_NAME,
          user: { cisId },
        })
      })
  }, [cisId])

  const { stop: stopGeneralists, start: startGeneralists } = usePoll(generalistsPoll, 5000)
  const { stop: stopDiscussions, start: startDiscussions } = usePoll(discussionPoll, 3000)
  const { stop: stopStats, start: startStats } = usePoll(statsPoll, 10000)
  const { stop: stopMyStatus, start: startMyStatus } = usePoll(myStatusPoll, 15000)

  useEffect(() => {
    if (!generalistsOpen || !isChatOverlayOpen || filterOverlay?.isOpen) stopGeneralists()
    if (generalistsOpen && isChatOverlayOpen && !filterOverlay?.isOpen) startGeneralists()

    if (isChatOverlayOpen) {
      startDiscussions()
      startStats()
      startMyStatus()
    } else {
      // If it's just a full page, then exiting the page will stop the poll for us. But if it's an overlay, we need to stop polling when the overlay is closed.
      stopDiscussions()
      stopStats()
      stopMyStatus()
    }
  }, [
    generalistsOpen,
    stopGeneralists,
    startGeneralists,
    isChatOverlayOpen,
    startDiscussions,
    stopDiscussions,
    startStats,
    stopStats,
    startMyStatus,
    stopMyStatus,
    filterOverlay?.isOpen,
  ])

  const setAvailable = useCallback(async () => {
    await setAvailability(!myStatus?.available)
    getMyGeneralist()
      .then(parseStatusAndSetLangOrder)
      .catch((reason) => {
        chatLog({
          msg: reason,
          level: LOG_LEVEL.ERROR,
          component: COMPONENT_NAME,
          user: { cisId },
        })
      })
    startGeneralists()
  }, [myStatus?.available, startGeneralists, parseStatusAndSetLangOrder, cisId])

  if (mockValue) {
    return mockValue
  }

  return {
    generalistsLangFilter: generalistsLangFilter || [],
    setGeneralistsLangFilter,
    stats,
    discussions,
    myStatus,
    setAvailable,
    userProfile,
    generalistsOpen,
    setGeneralistsOpen,
    filterOverlay,
    ...generalistsData,
  }
}

export default useHelperQueue
