import React, { useRef, useEffect, useState, Fragment } from 'react'
import { css, cx } from '@linaria/core'
import { useTranslation } from 'react-i18next'
import { boolAttr } from '@fs/zion-frontend-friends'
import Cache from '@fs/zion-cache'
import debounce from 'lodash.debounce'
import { MenuClose } from '@fs/zion-icon'
import PropTypes from 'prop-types'
import { useBodyScrollLock } from '@fs/zion-react-utils'
import {
  DraggableContainer,
  MoveHandle,
  BorderResizeHandles,
  ResizableBoundaries,
  useDraggableBoundingRef,
  useDraggableContainer,
} from '@fs/zion-ui-draggable'
import Portal from '../portal'
import {
  useAutoFocus,
  useEscHandler,
  GridStart,
  OpenCloseAnimation,
  Overlay,
  ResponsiveProvider,
  BorderScroller,
} from '../quarks-authorized-use-only'
import { H2, Theme, colors, IconButton, Row, WhiteTheme, Cell, MarginBox, Subheading, atTextDirection } from '..'
import { textDirection } from '../rtl-support/textDirection'
import { SupplementalOverlayContext } from './SupplementalOverlayProvider'
import { LayoutBandContext } from '../layout-band/LayoutBand'
import { usePageWidth } from '../responsive'
import { fitContentAreaCss } from '../scrim/Scrim'

const stackingCss = css`
  z-index: 2; /* Create a stacking context, so all things inside this overlay will be contained (and on top of the main ui) */
  pointer-events: none;
`
const overlayCss = css`
  display: flex;
  flex-direction: column;
  z-index: 2;
  background: ${colors.gray00};
  height: 100%;

  &[fullscreen] {
    position: fixed;
    top: 0;
    inset-inline-end: 0;
    bottom: 0;
    inset-inline-start: 0;
    width: 100vw;
    height: 100%;
    min-width: unset;
    margin: 0;
    max-height: calc(var(--page-content-height, 100vh) - var(--virtual-keyboard-height, 0));
    overscroll-behavior: contain; /* Prevents scroll chaining on mobile (FRONTIER-1772, FRONTIER-3177) */
  }
`
const moveHandleCss = css`
  // Prevent refresh issues on mobile devices when moving and resizing the overlay
  touch-action: none;

  &:has([data-move-handle]:focus-visible) {
    outline: 4px solid ${colors.transparent.gray60} !important;
    outline-offset: 4px;
    border-radius: 14px;
  }
`

const openCloseCss = css`
  display: flex;
  height: 100%;
  transform-origin: center;
`

const headerCss = css`
  --header-color: ${colors.gray100};
  background: var(--header-color) !important; // Because Theme/WhiteTheme wants this transparent, we have to override
  position: relative;
  transition: background 0.3s;
  flex-shrink: 0;

  &[data-color='red'] {
    --header-color: ${colors.red80};
  }
  &[data-color='green'] {
    --header-color: ${colors.green60};
  }
  &[data-color='blue'] {
    --header-color: ${colors.blue70};
  }
  &[data-color='purple'] {
    --header-color: ${colors.purple80};
  }
`

const desktopAnimStyles = {
  openStyles: { y: '0', opacity: 1, position: 'static', config: { tension: 300 } },
  closeStyles: { y: '0', opacity: 0, position: 'static', config: { tension: 300 } },
  derivedStyles: {
    transform: [['opacity'], (opacity) => `scale(${0.75 + opacity.toFixed(2) * 0.25})`],
  },
}
const fullscreenMobileAnimStyles = {
  openStyles: {
    opacity: 1,
    y: '0vh',
    position: 'fixed',
    top: 0,
    bottom: 0,
    insetInlineStart: 0,
    config: { tension: 250 },
  },
  closeStyles: {
    opacity: 1,
    y: '100vh',
    position: 'fixed',
    top: 0,
    bottom: 0,
    insetInlineStart: 0,
    config: { tension: 300 },
  },
}

const supplementalOverlayCache = new Cache({
  storeName: 'supplementalOverlayCache',
  type: 'session',
})

const debouncedSetItem = debounce((key, value) => {
  supplementalOverlayCache.setItem(key, value)
}, 1000)

const BleedableWrapper = (props) => (
  <MarginBox as={ResponsiveProvider} marginX="sm" marginY="nano">
    <GridStart {...props} />
  </MarginBox>
)

const contentWrapper = css`
  display: flex;
  flex-grow: 1;
  flex-direction: column;
  overflow: hidden;
`

// exporting for testing purposes (not public)
export const SupplementalOverlayContent = ({ children }) => (
  // The ResponsiveProvider needs to be outside of the BorderScroller or else content that has width-based heights (i.e. using --cell-width or --grid-width
  // values to determine height) will cause stroby resize loops at certain sizes due to the scrollbar changing the width of the ResponsiveProvider when it appears/disappears. (ZIONUI-1398)
  // NOTE: We have tried other methods (mainly trying to keep --cell-width and --grid-width consistent) to counteract this, but they both came with caveats.
  //  1. using negative margins makes the scrollbar overlap the content if there isn't enough margin.
  //  2. Adding the width of the scrollbar to the overlays is doable, but it is complicated, hard to maintain, can still behave a bit wonky sometimes.
  <ResponsiveProvider className={contentWrapper}>
    <BorderScroller>
      <MarginBox marginX="sm" marginY="nano">
        <GridStart>{children}</GridStart>
      </MarginBox>
    </BorderScroller>
  </ResponsiveProvider>
)

const padding = 12
const minMax = (val, min, max) => Math.min(Math.max(val, min), max)

function SupplementalOverlay({
  children,
  defaultWidth = 360,
  defaultHeight = 550,
  overlayKey,
  targetRef,
  header,
  subHeader,
  supplementalButtons = [],
  footer,
  headerColor = 'blue',
  anchor = false,
  strippedDownLayout = false,
  closeAffordanceProps = {},
  ...overlay
}) {
  const [t] = useTranslation()
  const isMobileFullscreen = usePageWidth()({ default: true, md: false })
  const [mouseInOverlay, setMouseInOverlay] = useState(false)
  const overlayRef = useRef()
  const supplementalOverlayWrapperRef = useRef()
  const onlyRunOnceRef = useRef(true)
  const textDirectionRef = useRef(textDirection())
  const [supplementalOverlayReady, setSupplementalOverlayReady] = useState(false)
  const initialPosition = { x: 0, y: 0, width: defaultWidth, height: defaultHeight }
  const [position, setPosition] = useDraggableContainer(initialPosition)

  useAutoFocus({
    isOpen: !overlay.transitioning && overlay.isOpen,
    enabled: true,
    containerRef: overlayRef,
  })

  useEscHandler({
    handler: overlay.close,
    enabled: overlay.isOpen,
  })

  useBodyScrollLock(overlay.isOpen && (isMobileFullscreen || mouseInOverlay), overlayRef)

  // Update overlay size and position in cache after user resizes/drags
  useEffect(() => {
    if (!onlyRunOnceRef.current && !anchor) debouncedSetItem(overlayKey, position)
    return () => debouncedSetItem.flush()
  }, [overlayKey, overlay.isOpen, anchor, position])

  // Clear flags allowing the positioning useEffect to run again.
  useEffect(() => {
    onlyRunOnceRef.current = true
    setSupplementalOverlayReady(false)
  }, [anchor])

  useEffect(() => {
    // Check if text direction has changed
    const currentDir = textDirection()
    if (currentDir !== textDirectionRef.current) {
      textDirectionRef.current = currentDir
      // Clear cache and force recalculation
      supplementalOverlayCache.removeItem(overlayKey)
      onlyRunOnceRef.current = true
    }

    // This needs to run once for each overlay, on initial mount
    if (onlyRunOnceRef.current) {
      onlyRunOnceRef.current = false
      // Update with size from cache
      supplementalOverlayCache.getItem(overlayKey).then((rect) => {
        if (!rect || anchor) {
          const targetRect = targetRef.current?.getBoundingClientRect?.() || {}
          rect = {
            x: targetRect.x || padding * atTextDirection({ ltr: 1, rtl: -1 }),
            y: (targetRect.bottom || padding - 4) + 4,
            width: defaultWidth,
            height: defaultHeight,
          }
        }

        const maxWidth = window.innerWidth - padding * 2
        const maxHeight = window.innerHeight - padding * 2
        const realWidth = minMax(rect.width, 300, maxWidth)
        const realHeight = minMax(rect.height, 400, maxHeight)

        const maxX = atTextDirection({
          ltr: (maxWidth - realWidth + padding) * 1,
          rtl: (maxWidth - realWidth + padding) * -1,
        })
        const maxY = maxHeight - realHeight + padding
        setPosition({
          width: realWidth,
          height: realHeight,
          x: atTextDirection({
            ltr: minMax(rect.x, padding, maxX),
            rtl: minMax(rect.x, maxX, padding * -1),
          }),
          y: minMax(rect.y, padding, maxY),
        })

        // Mark initialization as complete
        setSupplementalOverlayReady(true)
      })
    }
  }, [overlayKey, targetRef, setPosition, defaultWidth, defaultHeight, anchor])

  const getBounds = useDraggableBoundingRef(supplementalOverlayWrapperRef, 300, 200, padding)

  const ContentWrapper = strippedDownLayout ? Fragment : SupplementalOverlayContent

  return (
    <Portal context={SupplementalOverlayContext}>
      {/* this div below is necessary for the helptray bundle for bifrost styles */}
      <div className="supplemental-overlay-container">
        <div
          className={cx(fitContentAreaCss, stackingCss, 'supplemental-overlay-wrapper')}
          ref={supplementalOverlayWrapperRef}
        >
          <DraggableContainer
            style={!overlay.isOpen && !overlay.transitioning && { display: 'none' }}
            disabled={isMobileFullscreen}
            getBounds={getBounds}
            position={position}
            setPosition={setPosition}
            className={moveHandleCss}
          >
            <ResizableBoundaries boundaryRef={supplementalOverlayWrapperRef} />
            <OpenCloseAnimation
              onOpenFinished={overlay.handleTransitioned}
              onCloseFinished={overlay.handleTransitioned}
              isOpen={supplementalOverlayReady && overlay.isOpen}
              className={openCloseCss}
              {...(isMobileFullscreen ? fullscreenMobileAnimStyles : desktopAnimStyles)}
            >
              <Overlay ref={overlayRef} borderRadius={16} fixSize aria-modal="false" zVeil={2}>
                <Theme
                  style={{ pointerEvents: overlay.isOpen ? 'all' : 'none' }}
                  fullscreen={boolAttr(isMobileFullscreen)}
                  className={overlayCss}
                  onMouseEnter={() => setMouseInOverlay(true)}
                  onMouseLeave={() => setMouseInOverlay(false)}
                  onMouseDown={() => {
                    // Set all other supplemental overlays to z-index 1, then set this one to 2
                    document.querySelectorAll('.supplemental-overlay-wrapper').forEach((el) => {
                      el.style.zIndex = '1'
                    })
                    supplementalOverlayWrapperRef.current.style.zIndex = '2'
                  }}
                >
                  {/* HEADER */}
                  <WhiteTheme data-color={headerColor} className={headerCss}>
                    <MoveHandle>
                      <BleedableWrapper>
                        <H2 size="H5" data-full-width>
                          <Row gutters="xs">
                            <Cell growX alignY="middle">
                              {header}
                            </Cell>
                            {subHeader && (
                              <Subheading as="div" size="xs" data-full-width>
                                {subHeader}
                              </Subheading>
                            )}
                            <Row noShrinkX gutters="sm">
                              {supplementalButtons.map((button) => (
                                <Cell key={button.value} noShrinkX>
                                  {button}
                                </Cell>
                              ))}
                              <IconButton
                                title={t('common-ui:close.action', 'Close')}
                                Icon={MenuClose}
                                onClick={overlay.close}
                                {...closeAffordanceProps}
                                noShrinkX
                              />
                            </Row>
                          </Row>
                        </H2>
                      </BleedableWrapper>
                    </MoveHandle>
                  </WhiteTheme>

                  <LayoutBandContext.Provider value>
                    {/* CONTENT */}
                    <ContentWrapper>{children}</ContentWrapper>

                    {/* FOOTER */}
                    {footer && <BleedableWrapper>{footer}</BleedableWrapper>}
                  </LayoutBandContext.Provider>
                  <BorderResizeHandles />
                </Theme>
              </Overlay>
            </OpenCloseAnimation>
          </DraggableContainer>
        </div>
      </div>
    </Portal>
  )
}

export default React.memo(SupplementalOverlay)

SupplementalOverlay.propTypes = {
  /** Unique identifier for this overlay. Used to cache position and size. */
  overlayKey: PropTypes.string.isRequired,

  /** Header color. Also changes color of the resize icon. */
  headerColor: PropTypes.oneOf(['blue', 'green', 'yellow', 'red', 'purple', 'gray']),

  /** Header content. */
  header: PropTypes.oneOfType([PropTypes.string, PropTypes.element]).isRequired,

  /** Subheader content. */
  subHeader: PropTypes.oneOfType([PropTypes.string, PropTypes.element]),

  /** Allows additional buttons to be added to the Heading (besides the built in `close` button)
   *
   * **IMPORTANT:** Whether you're adding one or multiple buttons you MUST put them in an array so they align horizontally
   */
  supplementalButtons: PropTypes.arrayOf(PropTypes.node),

  /** Props to customize the close affordance. Accepts any IconButton props.
   * Defaults to MenuClose icon with localized "Close" title.
   */
  closeAffordanceProps: PropTypes.shape({
    Icon: PropTypes.elementType,
    iconDirection: PropTypes.string,
    title: PropTypes.string,
  }),

  /** Footer content. */
  footer: PropTypes.oneOfType([PropTypes.string, PropTypes.element]),

  /** Whether the layout of SupplementalOverlay needs to be simplified, without Bleed and BorderScroller
   *
   * **REQUIRED:** If you enable this, you must do the following:
   * - Make your content margins be 12px,
   * - Wrap your own content in a BorderScroller,
   * - and Put in your own ResponsiveProvider and GridStart inside of the BorderScroller.
   */
  strippedDownLayout: PropTypes.bool,

  /** Default width if not previously stored in the cache */
  defaultWidth: PropTypes.number,

  /** Default height if not previously stored in the cache */
  defaultHeight: PropTypes.number,
}
