import React, { createContext, useState, useEffect, useContext } from 'react'
import { usePermission } from '@fs/zion-permissions'
import useHelperQueue from '../hooks/useHelperQueue'
import useChatFlags from '../hooks/useChatFlags'
import { getMyGeneralist } from '../services/helperQueue/helperQueueService'
import useHandleChatErrors from '../hooks/useHandleChatErrors'
import useChatLog from '../hooks/useChatLog'

export const helperContext = createContext({})

export const useHelperContext = () => {
  return useContext(helperContext)
}

export default function HelperProvider({ mockValue, isChatOverlayOpen, children }) {
  const value = useHelperQueue({ mockValue, isChatOverlayOpen })
  return <helperContext.Provider value={value}>{children}</helperContext.Provider>
}

export function ChatHelperProvider({ mockValue, isChatOverlayOpen, children }) {
  const { messagingChatHelperIsOn } = useChatFlags()
  // This can happen if the user was a helper in a previous year (and therefore has the RtcHelpDeskHelper permission), but hasn't signed up again this year (no helper data from the helpdesk API)
  const [helperIsStale, setHelperIsStale] = useState(false)
  const [isHelper, status] = usePermission('RtcHelpDeskHelper', 'RtcHelpDeskContext')
  const { log } = useChatLog({ component: '[HelperProvider]' })
  const { handleBasicError } = useHandleChatErrors({ log })

  useEffect(() => {
    let isUnmounted = false

    const checkHelperStatus = async () => {
      try {
        if (messagingChatHelperIsOn && isHelper) {
          const { data } = await getMyGeneralist()

          if (!isUnmounted && !data) {
            setHelperIsStale(true)
          }
        }
      } catch (err) {
        if (!isUnmounted) {
          handleBasicError(err, { moreInfo: 'Failed to check helper status' })
        }
      }
    }

    checkHelperStatus()

    return () => {
      isUnmounted = true
    }
  }, [isHelper, messagingChatHelperIsOn, handleBasicError])

  if (status === 'loading') return null

  return messagingChatHelperIsOn && isHelper && !helperIsStale ? (
    <HelperProvider mockValue={mockValue} isChatOverlayOpen={isChatOverlayOpen}>
      {children}
    </HelperProvider>
  ) : (
    <>{children}</>
  )
}
