import axios from '@fs/zion-axios'

const baseServiceUrl = '/service/rootstech/rtc2022'

export const getStats = () => {
  return axios.get(`${baseServiceUrl}/helpdesk/stats`)
}

export const getDiscussions = () => {
  return axios.get(`${baseServiceUrl}/helpdesk/discussions/available`)
}

export const assignDiscussion = (cisId, language = 'en') => {
  return axios.post(`${baseServiceUrl}/helpdesk/discussions/assignments/${cisId}?language=${language}`)
}

export const getGeneralists = (langs = '') => {
  const params = langs ? { language: langs } : {}
  return axios.get(`${baseServiceUrl}/helpdesk/generalists`, { params })
}

export const getMyGeneralist = () => {
  return axios.get(`${baseServiceUrl}/helpdesk/generalists/CURRENT`)
}

// using temporarily until actual flow is set up in RT app
export const postGeneralist = (languages = ['en']) => {
  // return axios.delete(`/service/rootstech/rtc2022/helpdesk/generalists/CURRENT`) to delete for testing
  return axios.post(`${baseServiceUrl}/helpdesk/generalists`, { languages: languages.join(' ') })
}

export const setAvailability = (status) => {
  return axios.post(`${baseServiceUrl}/helpdesk/generalists/CURRENT/availability/${Boolean(status)}`)
}
