import {
  CHANNEL_CATEGORY_MAP,
  CHANNEL_TYPE,
  EVENT_CHANNEL_TYPES,
  RESTRICTED_CATEGORY_MAP,
  TAB_CATEGORY,
} from '../../services/fsChat/fsChannelEnums'
import { LOG_LEVEL } from '../../global/chatLog'

export const QUERY_CHANNELS_PAGE_SIZE = 20

export async function findExistingChat(channels, client, cid, log) {
  let channel = channels.find((chat) => {
    return chat.cid === cid
  })

  if ((!channel || channel.disconnected) && client && cid) {
    try {
      const results = await client.queryChannels({ cid: { $eq: cid } })
      channel = results[0]
    } catch (error) {
      if (log) {
        log(
          { msg: `Failed to query channel by cid: ${cid}. Error: ${error}`, level: LOG_LEVEL.ERROR },
          { channelId: cid, httpStatus: error?.response?.status }
        )
      }
      throw error
    }
  }
  return channel
}

export const isShadowedChannel = (channel) => {
  // Hide any empty direct channels due to all the messages being sent from a shadow banned user
  if (channel?.type !== CHANNEL_TYPE.FS_DIRECT) return false

  const messages = channel?.state?.messageSets?.[0]?.messages
  const isAllMessagesShadowedOrDeleted = messages?.every((message) => message.shadowed || message.type === 'deleted')

  // We want to mark these hidden channels as read to not mess up the unread count
  if (isAllMessagesShadowedOrDeleted && channel?.countUnread() > 0) channel?.markRead()

  return isAllMessagesShadowedOrDeleted
}

export async function queryUserUnreadChannels({ client, offset = 0, log }) {
  if (!client?.userID || typeof client.userID !== 'string') {
    // Unexpected — healthy connection should always have a userID.
    if (client?.wsConnection?.isHealthy) {
      const err = new Error(`queryUserUnreadChannels: client.userID is not a valid string (got: ${client?.userID})`)
      if (log) log({ msg: err.message, level: LOG_LEVEL.ERROR }, { offset, userID: client?.userID })
      throw err
    }
    // disconnectUser() clears userID synchronously — overlay is closing, bail out silently.
    return []
  }
  try {
    return await client.queryChannels(
      {
        has_unread: true,
        members: { $in: [client.userID] },
        type: { $ne: CHANNEL_TYPE.FS_THREAD },
      },
      [
        {
          last_message_at: -1,
        },
      ],
      {
        watch: true,
        state: true,
        limit: QUERY_CHANNELS_PAGE_SIZE,
        offset,
      }
    )
  } catch (error) {
    if (log) {
      log(
        { msg: `Failed to query user unread channels. Error: ${error}`, level: LOG_LEVEL.ERROR },
        { offset, httpStatus: error?.response?.status }
      )
    }
    throw error
  }
}

export async function queryPageOfChannelsByType({ client, types, offset = 0, hidden = false, log }) {
  if (!client?.userID || typeof client.userID !== 'string') {
    // Unexpected — healthy connection should always have a userID.
    if (client?.wsConnection?.isHealthy) {
      const err = new Error(`queryPageOfChannelsByType: client.userID is not a valid string (got: ${client?.userID})`)
      if (log) log({ msg: err.message, level: LOG_LEVEL.ERROR }, { types, offset, hidden, userID: client?.userID })
      throw err
    }
    // disconnectUser() clears userID synchronously — overlay is closing, bail out silently.
    return []
  }
  const filter = {
    type: { $in: types },
    members: { $in: [client?.userID] },
    hidden,
  }
  const sort = [{ last_message_at: -1 }]

  try {
    const channels = await client?.queryChannels(filter, sort, {
      watch: true, // this is the default
      state: true,
      limit: QUERY_CHANNELS_PAGE_SIZE,
      offset,
    })

    const filteredChannels = channels.filter((channel) => !isShadowedChannel(channel))

    return filteredChannels
  } catch (error) {
    if (log) {
      log(
        {
          msg: `Failed to query channels by type. Types: ${types.join(', ')}. Error: ${error}`,
          level: LOG_LEVEL.ERROR,
        },
        { types, offset, hidden, httpStatus: error?.response?.status }
      )
    }
    throw error
  }
}

export async function queryChannelsByType({ client, type, offset = 0, log }) {
  const filter = {
    type: { $eq: type },
    // Explicitly filter these out to work around a known Stream issue that otherwise returns partial pages (CCR-361)
    hidden: false,
    disabled: false,
  }
  const sort = [{ name: 1, last_message_at: -1 }]
  try {
    return await client.queryChannels(filter, sort, {
      watch: false,
      state: true,
      limit: QUERY_CHANNELS_PAGE_SIZE,
      offset,
    })
  } catch (error) {
    if (log) {
      log(
        { msg: `Failed to query channels by type: ${type}. Error: ${error}`, level: LOG_LEVEL.ERROR },
        { type, offset, httpStatus: error?.response?.status }
      )
    }
    throw error
  }
}

// Deprecated - old left panel redesign
export async function queryChatUserChannels({ client, restrictToManagedGroups, log }) {
  // Though it would slightly improve performance to make all of these requests at once, we are making them separately
  // because Stream does not provide operators to limit the number of results returned per type.
  const chatChannelGroups = await Promise.all(
    Object.values(restrictToManagedGroups ? RESTRICTED_CATEGORY_MAP : CHANNEL_CATEGORY_MAP).map(({ types }) => {
      return queryPageOfChannelsByType({ client, types, log })
    })
  )

  return chatChannelGroups.reduce(
    (previousValue, currentValueChannels) => {
      const { channels, hasMoreChannels } = previousValue
      if (currentValueChannels?.length > 0) {
        const channelCategory = getChannelCategoryKeyForChannel(currentValueChannels[0])
        hasMoreChannels[channelCategory] = currentValueChannels.length >= QUERY_CHANNELS_PAGE_SIZE
        return { channels: [...channels, ...currentValueChannels], hasMoreChannels }
      }
      return previousValue
    },
    { channels: [], hasMoreChannels: {} }
  )
}

export async function queryParentChannels({ client, channels, threads, nonQueryableChannelIds, log }) {
  // Build list of parent channel CIDs that are required for the provided threads but
  // are not already in `channels` and have not already been checked.
  const existingChannelCids = new Set(channels.map((c) => c.cid))
  const missingCids = []

  threads.forEach((thread) => {
    const cid = thread?.state?.getLatestValue()?.channel?.cid
    const notAlreadyLoaded = !existingChannelCids.has(cid)
    const notMarkedNonQueryable = !nonQueryableChannelIds.includes(cid)
    if (notAlreadyLoaded && notMarkedNonQueryable) missingCids.push(cid)
  })

  if (missingCids.length === 0 || !client?.userID) {
    return { parentChannels: [], parentChannelIdsNotFound: [] }
  }

  try {
    const parentChannels = await client.queryChannels(
      { cid: { $in: missingCids }, members: { $in: [client.userID] } },
      [{ last_message_at: -1 }],
      { watch: true, state: true }
    )

    // Any cid we attempted to fetch that didn't come back is considered "not found".
    const parentChannelIdsNotFound = missingCids.filter((cid) => !parentChannels.some((c) => c.cid === cid)) || []
    return { parentChannels, parentChannelIdsNotFound }
  } catch (error) {
    if (log) {
      log(
        {
          msg: `Failed to query parent channels. CIDs: ${missingCids.join(', ')}. Error: ${error}`,
          level: LOG_LEVEL.ERROR,
        },
        { missingCids, httpStatus: error?.response?.status }
      )
    }
    throw error
  }
}

export const getChildThreadChannels = async ({ client, cid, log }) => {
  if (!client?.userID || typeof client.userID !== 'string') {
    // Unexpected — healthy connection should always have a userID.
    if (client?.wsConnection?.isHealthy) {
      const err = new Error(`getChildThreadChannels: client.userID is not a valid string (got: ${client?.userID})`)
      if (log) log({ msg: err.message, level: LOG_LEVEL.ERROR }, { cid, userID: client?.userID })
      throw err
    }
    // disconnectUser() clears userID synchronously — overlay is closing, bail out silently.
    return []
  }
  try {
    // remove this with fs_thread write removal
    const results = await client?.queryChannels(
      {
        type: { $eq: CHANNEL_TYPE.FS_THREAD },
        fs_parent_channel_cid: { $eq: cid },
        members: { $in: [client?.userID] },
      },
      [{ last_message_at: -1 }],
      {
        watch: false,
        state: true,
        limit: 100,
      }
    )
    return results || []
  } catch (error) {
    if (log) {
      log(
        {
          msg: `Failed to query child thread channels. Parent CID: ${cid}. Error: ${error}`,
          level: LOG_LEVEL.ERROR,
        },
        { parentChannelId: cid, httpStatus: error?.response?.status }
      )
    }
    // Return empty array instead of throwing to allow graceful degradation
    return []
  }
}

export async function loadChannelsForCategory({ category, client, offset = 0, restrictToManagedGroups = false, log }) {
  let channels = []
  switch (category) {
    case TAB_CATEGORY.ALL:
      {
        const types = restrictToManagedGroups
          ? [CHANNEL_TYPE.FS_MANAGED]
          : Object.values(CHANNEL_TYPE).filter((type) => type !== CHANNEL_TYPE.FS_THREAD)
        channels = await queryPageOfChannelsByType({ client, types, offset, log })
      }
      break
    case TAB_CATEGORY.UNREAD:
      {
        const unreadChannels = await queryUserUnreadChannels({ client, offset, log })
        channels = restrictToManagedGroups
          ? unreadChannels.filter((c) => c.type === CHANNEL_TYPE.FS_MANAGED)
          : unreadChannels
      }
      break
    case TAB_CATEGORY.DIRECT:
      channels = await queryPageOfChannelsByType({ client, types: [CHANNEL_TYPE.FS_DIRECT], offset, log })
      break
    case TAB_CATEGORY.FAMILY_GROUPS:
      channels = await queryPageOfChannelsByType({ client, types: [CHANNEL_TYPE.FS_MANAGED], offset, log })
      break
    case TAB_CATEGORY.EVENTS:
      {
        const channelArrays = await Promise.all(
          EVENT_CHANNEL_TYPES.map((type) => queryPageOfChannelsByType({ client, types: [type], offset, log }))
        )
        channels = channelArrays.flat()
      }
      break
    default:
      channels = []
  }
  return channels
}

// INTERNAL
function getChannelCategoryKeyForChannel(channel) {
  return Object.values(CHANNEL_CATEGORY_MAP).find(({ types }) => types.includes(channel.type))?.key
}
