import { formatDistanceStrict } from '@fs/zion-locale/date-fns'

export const langs = ['zh-hans', 'zh', 'en', 'fr', 'de', 'it', 'ja', 'ko', 'pt', 'ru', 'es']

export const getLangMapping = (langCode) => {
  const langObj = {
    en: 'English',
    es: 'Spanish',
    pt: 'Portuguese',
    fr: 'French',
    de: 'German',
    it: 'Italian',
    ru: 'Russian',
    ko: 'Korean',
    ja: 'Japanese',
    zh: 'Chinese (traditional) ',
    'zh-hans': 'Chinese (simplified) ',
  }

  return langObj[langCode] || 'All Others'
}

export const discussionTimeStampToString = (stamp, includeSeconds = false) => {
  if (stamp) {
    const makeSureItsUTC = stamp.endsWith('Z') ? stamp : `${stamp}Z`
    return `(${formatDistanceStrict(new Date(makeSureItsUTC), new Date(), { includeSeconds })})`
  }
  return stamp
}

export const filterGeneralistsByLanguage = (generalist, displayedLangs) => {
  if (!displayedLangs || displayedLangs.length === 0) {
    return true
  }
  const generalistLangs = generalist.languages.split(',').map((lang) => lang.trim())
  return generalistLangs.some((lang) => displayedLangs.includes(lang))
}
