import { useMemo } from 'react'
import { useOverlay } from '@fs/zion-ui'
import { usePermission } from '@fs/zion-permissions'
import useChatFlags from './useChatFlags'
import { useHelperContext } from '../chat-helper-tab/HelperProvider'

/**
 * Hook that wraps an overlay object to intercept close actions
 * when a helper is available, showing a confirmation dialog first.
 *
 * @param {Object} overlay - The overlay object from useOverlay()
 * @returns {Object} - Contains wrappedOverlay and confirmationOverlay
 */
export default function useHelperConfirmationOverlay(overlay) {
  const { messagingChatHelperIsOn } = useChatFlags()
  const [isHelper, permissionStatus] = usePermission('RtcHelpDeskHelper', 'RtcHelpDeskContext')
  const confirmationOverlay = useOverlay()

  const helperContext = useHelperContext()
  const helperIsAvailable = helperContext?.myStatus?.available || false

  const shouldCheckHelper = messagingChatHelperIsOn && isHelper && permissionStatus !== 'loading'

  const wrappedOverlay = useMemo(
    () => ({
      ...overlay,
      handleClick: (event) => {
        // If overlay is closing and helper is available, show confirmation first
        if (overlay.isOpen && shouldCheckHelper && helperIsAvailable) {
          confirmationOverlay.open()
        } else {
          overlay.handleClick(event)
        }
      },
      close: () => {
        // If helper is available, show confirmation first
        if (shouldCheckHelper && helperIsAvailable) {
          confirmationOverlay.open()
        } else {
          overlay.close()
        }
      },
    }),
    [overlay, shouldCheckHelper, helperIsAvailable, confirmationOverlay]
  )

  return {
    wrappedOverlay,
    confirmationOverlay,
  }
}
