/* eslint-disable no-console -- Console statements are intentional for debug tools */
/**
 * Chat Websocket Debug Utilities
 *
 * Exposes debugging tools to the browser console for testing websocket
 * disconnection/reconnection scenarios.
 *
 * Usage:
 *   window.__CHAT_WS_DEBUG__.simulateTimeout()  // Simulate a real timeout scenario
 *   window.__CHAT_WS_DEBUG__.disconnect()       // Manually disconnect the client
 *   window.__CHAT_WS_DEBUG__.reconnect()        // Manually reconnect the client
 *   window.__CHAT_WS_DEBUG__.status()           // Check current connection status
 *   window.__CHAT_WS_DEBUG__.help()             // Show available commands
 */

let client = null

/**
 * Initialize the debug tooling with the Stream client
 */
export function initChatWebsocketDebug(streamClient) {
  client = streamClient
  if (typeof window !== 'undefined') {
    window.__CHAT_WS_DEBUG__ = {
      simulateTimeout: () => {
        if (!client?.wsConnection?.ws) {
          console.warn('[Chat WS Debug] No websocket available. Chat may not be initialized yet.')
          return
        }
        console.log('[Chat WS Debug] Simulating timeout by forcefully closing underlying WebSocket...')
        console.log('[Chat WS Debug] This mimics what happens during a real network timeout.')
        // Close the underlying WebSocket without going through Stream's clean closeConnection
        // This forces Stream to detect the connection loss and auto-reconnect
        client.wsConnection.ws.close()
        console.log('[Chat WS Debug] ✅ WebSocket forcefully closed. Stream should auto-detect and reconnect.')
      },

      disconnect: async () => {
        if (!client) {
          console.warn('[Chat WS Debug] No client available')
          return
        }
        try {
          console.log('[Chat WS Debug] Manually disconnecting stream client...')
          await client.closeConnection()
          console.log('[Chat WS Debug] ✅ Client disconnected successfully')
        } catch (error) {
          console.error('[Chat WS Debug] ❌ Error disconnecting client:', error)
        }
      },

      reconnect: async () => {
        if (!client) {
          console.warn('[Chat WS Debug] No client available')
          return
        }
        try {
          console.log('[Chat WS Debug] Manually reconnecting stream client...')
          await client.openConnection()
          console.log('[Chat WS Debug] ✅ Client reconnected successfully')
        } catch (error) {
          console.error('[Chat WS Debug] ❌ Error reconnecting client:', error)
        }
      },

      status: () => {
        if (!client) {
          console.log('[Chat WS Debug] ❌ No client available')
          return null
        }

        const wsConnection = client.wsConnection
        const status = {
          isHealthy: wsConnection?.isHealthy ?? false,
          isDisconnected: wsConnection?.isDisconnected ?? true,
          connectionID: wsConnection?.connectionID ?? null,
          isConnecting: wsConnection?.isConnecting ?? false,
          user: client.user?.id ?? null,
          anonymous: client.anonymous ?? false,
        }

        console.log('[Chat WS Debug] Connection Status:', {
          '🟢 Healthy': status.isHealthy,
          '🔴 Disconnected': status.isDisconnected,
          '🔄 Connecting': status.isConnecting,
          '🆔 Connection ID': status.connectionID,
          '👤 User ID': status.user,
          '🔓 Anonymous': status.anonymous,
        })

        return status
      },

      info: () => {
        if (!client) {
          console.log('[Chat WS Debug] ❌ No client available')
          return null
        }

        const wsConnection = client.wsConnection
        const now = new Date()
        const lastEventTime = wsConnection?.lastEvent
        const timeSinceLastEvent = lastEventTime ? now.getTime() - lastEventTime.getTime() : null

        const info = {
          userID: client.userID,
          isHealthy: wsConnection?.isHealthy,
          isDisconnected: wsConnection?.isDisconnected,
          isConnecting: wsConnection?.isConnecting,
          connectionID: wsConnection?.connectionID,
          consecutiveFailures: wsConnection?.consecutiveFailures,
          totalFailures: wsConnection?.totalFailures,
          lastEventTime: lastEventTime?.toISOString(),
          timeSinceLastEventMs: timeSinceLastEvent,
          timeSinceLastEventSeconds: timeSinceLastEvent ? Math.floor(timeSinceLastEvent / 1000) : null,
          connectionCheckTimeoutMs: wsConnection?.connectionCheckTimeout,
          pingIntervalMs: wsConnection?.pingInterval,
        }

        console.log('[Chat WS Debug] Connection Info:', info)
        console.log(
          '[Chat WS Debug] Health Check: Expects events every ~35s. If no event for longer, connection is unhealthy.'
        )
        return info
      },

      monitorEvents: (duration = 60000) => {
        if (!client) {
          console.warn('[Chat WS Debug] No client available')
          return null
        }

        console.log(`[Chat WS Debug] Monitoring all Stream events for ${duration / 1000} seconds...`)
        const eventListener = client.on((event) => {
          if (event.type?.includes('connection') || event.type?.includes('health')) {
            console.log('[Chat WS Debug] 🔔 Connection Event:', {
              type: event.type,
              online: event.online,
              timestamp: new Date().toISOString(),
              event,
            })
          }
        })

        setTimeout(() => {
          eventListener.unsubscribe()
          console.log('[Chat WS Debug] ⏹️ Event monitoring stopped')
        }, duration)

        console.log('[Chat WS Debug] ⏺️ Event monitoring started (connection events only)')
        return eventListener
      },

      help: () => {
        console.log(`
╔════════════════════════════════════════════════════════════════╗
║           Chat Websocket Debug Utilities - Help                ║
╚════════════════════════════════════════════════════════════════╝

Available Commands:
-------------------
  __CHAT_WS_DEBUG__.simulateTimeout()
    → Simulate a real websocket timeout scenario
    → Force closes the underlying WebSocket
    → Stream will auto-detect and reconnect
    → Use this to test the channel requery fix

  __CHAT_WS_DEBUG__.disconnect()
    → Manually disconnect the stream client
    → Uses Stream's clean closeConnection() method
    → Returns a promise

  __CHAT_WS_DEBUG__.reconnect()
    → Manually reconnect the stream client
    → Uses Stream's openConnection() method
    → Returns a promise

  __CHAT_WS_DEBUG__.status()
    → Check current connection status (healthy/disconnected/connecting)

  __CHAT_WS_DEBUG__.info()
    → Get detailed connection information and failure counts

  __CHAT_WS_DEBUG__.monitorEvents([durationMs])
    → Monitor connection-related events for specified duration
    → Default: 60000ms (1 minute)
    → Useful for debugging event flow

  __CHAT_WS_DEBUG__.help()
    → Show this help message

Testing Instructions for QA:
-----------------------------
  1. Open a chat channel

  2. Run: __CHAT_WS_DEBUG__.simulateTimeout()

  3. Wait for Stream to automatically reconnect (usually 2-5 seconds)

  4. Send a message in the chat
     - Message should send successfully
     - You should receive new messages from others

  5. Verify the channel is working properly after reconnection

  6. Check status: __CHAT_WS_DEBUG__.status()
     - Should show healthy connection

Diagnosing User-Reported Disconnections:
-----------------------------------------
  If a user reports chat disconnected after being idle:

  1. Ask them to open console and run: __CHAT_WS_DEBUG__.info()

  2. Look for:
     - timeSinceLastEventSeconds > 35-40 = health check failed
     - consecutiveFailures > 0 = reconnection attempts
     - totalFailures = lifetime failure count

  3. Check browser console for:
     - "connection.changed event fired" logs
     - These logs show when/why connection changed
     - Look for patterns in timing

  Note: Stream health checks expect events every ~35 seconds.
  If no events arrive, the connection is marked unhealthy and
  automatic reconnection is triggered.
`)
      },
    }

    // Show help on initialization
    console.log('[Chat WS Debug] 🛠️ Websocket debugging tools loaded!')
    console.log('[Chat WS Debug] Type __CHAT_WS_DEBUG__.help() for usage information')
  }
}

/**
 * Clean up debug tooling
 */
export function cleanupChatWebsocketDebug() {
  client = null
  if (typeof window !== 'undefined') {
    delete window.__CHAT_WS_DEBUG__
  }
}
