import { Observable } from '@fs/zion-frontend-friends'
import HelpTutorial, { HelpTutorialSlide, useHelpTutorial } from '@fs/zion-help-tutorial'
import { Link } from '@fs/zion-router'
import { Separator } from '@fs/zion-ui'
import React from 'react'
import { useTranslation, Trans } from 'react-i18next'

import slide1Image from '../images/help-overview/slide1.svg'
import slide2Image from '../images/help-overview/slide2.svg'
import slide3Image from '../images/help-overview/slide3.svg'
import slide4Image from '../images/help-overview/slide4.svg'
import slide5Image from '../images/help-overview/slide5.svg'
import { useChatProviderContext } from '../providers/useChatProviderContext'

export default function ChatHelpOverview() {
  const helpTutorial = useHelpTutorial('chat.overview')
  const { forceBypassStartupDialogs } = useChatProviderContext()
  const [t] = useTranslation()

  const tutorialTitle = t('chat.help.heading', 'FamilySearch Chat Basics')
  const tutorialDescription = t('chat.help.message', 'Take a moment to learn the basics about FamilySearch Chat.')

  return (
    <Observable>
      <HelpTutorial
        tutorialTitle={tutorialTitle}
        tutorialDescription={tutorialDescription}
        endHeader={false}
        {...helpTutorial}
        // Using this internal implementation detail to force the tutorial to skip the ad - if HelpTutorial changes this implementation, it may not work in the future
        shouldShowAd={helpTutorial.shouldShowAd && forceBypassStartupDialogs}
      >
        <HelpTutorialSlide
          imageAlt=""
          imageSrc={slide1Image}
          imgBleed
          heading={t('chat.help-1.heading', 'Welcome to FamilySearch Chat!')}
          content={
            <>
              {t(
                'chat.help-1.message',
                'The Chat tool makes is for collaborating and reaching out to other people on FamilySearch. It can be turned on or off in your account settings.'
              )}
              <Separator />
              {t('chat.help-1a.message', "Let's take a look at some of its most important features.")}
            </>
          }
        />
        <HelpTutorialSlide
          imageAlt=""
          imageSrc={slide2Image}
          imgBleed
          heading={t('chat.help-2.heading', 'Quickly Send a Message')}
          content={t(
            'chat.help-2.message',
            'To start a message, click on a contributor’s Contact ID. Contact IDs are located in the Chat directory or anywhere a person has added information.'
          )}
        />
        <HelpTutorialSlide
          imageAlt=""
          imageSrc={slide3Image}
          imgBleed
          heading={t('chat.help-3.heading', 'Collaborate more easily')}
          content={
            <>
              {t(
                'chat.help-3.message',
                `You can send a message to as many as {num} people.`,
                { num: 10 } // will need to be updated when limit is increased
              )}
              <Separator />
              {t(
                'chat.help-3a.message',
                'Entering an ancestor’s Tree ID into the conversation creates a direct link to their profile page.'
              )}
            </>
          }
        />
        <HelpTutorialSlide
          imageAlt=""
          imageSrc={slide4Image}
          imgBleed
          heading={t('chat.help-4.heading', 'Manage your workspace')}
          content={
            <>
              {t(
                'chat.help-4.message',
                'The chat window fits over the page and can be moved or resized so that it doesn’t get in the way.'
              )}
              <Separator />
              {t(
                'chat.help-4a.message',
                'This is so you can send a receive messages without losing your place on the FamilySearch website.'
              )}
            </>
          }
        />
        <HelpTutorialSlide
          imageAlt=""
          imageSrc={slide5Image}
          imgBleed
          heading={t('chat.help-5.heading', 'Manage your conversations')}
          content={
            <>
              {t(
                'chat.help-5.message',
                'Click the menu at the top of the Chat window to mute a conversation, block a sender, or report abuse.'
              )}
              <Separator />
              <Trans
                i18nKey="chat.help-5a.message"
                defaults="Finally, your account settings has a toggle for including your profile information in directory search results. If you can’t find a friend or family member in Chat, it could be that they have flipped this toggle to off."
                components={[<b />]}
              />
              <Separator />
              <Trans
                i18nKey="chat.help-5b.message"
                defaults="<0>Learn more</0> about Chat on the FamilySearch blog."
                components={[
                  <Link to="https://www.familysearch.org/en/blog/new-familysearch-chat" target="_blank" wayfinding />,
                ]}
              />
            </>
          }
        />
      </HelpTutorial>
    </Observable>
  )
}
