import { useEffect } from 'react'

export default function usePanelArrowNavigation({ leftContent, rightContent, threadContent, extraWide }) {
  useEffect(() => {
    function focusRightPanel() {
      rightContent.current?.focus()
    }
    function focusLeftPanel() {
      leftContent.current?.focus()
    }
    function focusThreadPanel() {
      threadContent.current?.focus()
    }

    const handleKeyDown = (event) => {
      const active = document.activeElement
      const tag = active?.tagName?.toLowerCase()
      const isEditable = active?.isContentEditable
      if (tag === 'input' || tag === 'textarea' || isEditable) return

      if (event.key === 'ArrowRight') {
        if (leftContent.current?.contains(active)) {
          focusRightPanel()
        } else if (rightContent.current?.contains(active) && extraWide) {
          focusThreadPanel()
        }
      } else if (event.key === 'ArrowLeft') {
        if (threadContent.current?.contains(active)) {
          focusRightPanel()
        } else if (rightContent.current?.contains(active)) {
          focusLeftPanel()
        }
      }
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [extraWide, leftContent, rightContent, threadContent])
}
