import React, { useContext, useReducer } from 'react'

export const actionTypes = {
  SET_PENDING_ARTIFACT_ATTACHMENTS: 'SET_PENDING_ARTIFACT_ATTACHMENTS',
  ADD_PENDING_ABOUT_ATTACHMENT: 'ADD_PENDING_ABOUT_ATTACHMENT',
  CLEAR_PENDING_ABOUT_ATTACHMENT: 'CLEAR_PENDING_ABOUT_ATTACHMENT',
  CLEAR_ALL_PENDING_ATTACHMENTS: 'CLEAR_ALL_PENDING_ATTACHMENTS',
  SET_PENDING_MESSAGE_TEXT: 'SET_PENDING_MESSAGE_TEXT',
  CLEAR_PENDING_MESSAGE_TEXT: 'CLEAR_PENDING_MESSAGE_TEXT',
}

const initialState = {
  pendingArtifactAttachments: [],
  pendingAboutAttachment: {},
  pendingMessageText: '',
}

const attachmentStateReducer = (state, action) => {
  switch (action.type) {
    case actionTypes.SET_PENDING_ARTIFACT_ATTACHMENTS:
      return { ...state, pendingArtifactAttachments: action.pendingArtifactAttachments }
    case actionTypes.ADD_PENDING_ABOUT_ATTACHMENT:
      return { ...state, pendingAboutAttachment: action.aboutAttachment }
    case actionTypes.CLEAR_PENDING_ABOUT_ATTACHMENT:
      return { ...state, pendingAboutAttachment: {} }
    case actionTypes.CLEAR_ALL_PENDING_ATTACHMENTS:
      return { ...state, pendingAboutAttachment: {}, pendingArtifactAttachments: [] }
    case actionTypes.SET_PENDING_MESSAGE_TEXT:
      return { ...state, pendingMessageText: action.pendingMessageText }
    case actionTypes.CLEAR_PENDING_MESSAGE_TEXT:
      return { ...state, pendingMessageText: '' }
    default:
      return state
  }
}

const ChatAttachmentsContext = React.createContext()
const ChatAttachmentsDispatchContext = React.createContext()

export const useChatAttachmentsState = () => {
  return useContext(ChatAttachmentsContext)
}

export const useChatAttachmentsDispatch = () => {
  return useContext(ChatAttachmentsDispatchContext)
}

export function useChatAttachmentsProviderData() {
  const [chatAttachmentsState, chatAttachmentsDispatch] = useReducer(attachmentStateReducer, initialState)
  return { chatAttachmentsState, chatAttachmentsDispatch }
}

export default function ChatAttachmentsProvider({ children, chatAttachmentsProviderData }) {
  const { chatAttachmentsState, chatAttachmentsDispatch } = chatAttachmentsProviderData

  return (
    <ChatAttachmentsContext.Provider value={chatAttachmentsState}>
      <ChatAttachmentsDispatchContext.Provider value={chatAttachmentsDispatch}>
        {children}
      </ChatAttachmentsDispatchContext.Provider>
    </ChatAttachmentsContext.Provider>
  )
}
